import { useState, useContext } from 'react';
import { JobContext } from '../context/JobContext';
import LoadingSpinner from '../components/LoadingSpinner';

const PostJobPage = () => {
  const { postJob } = useContext(JobContext);
  const [title, setTitle] = useState('');
  const [description, setDescription] = useState('');
  const [requirements, setRequirements] = useState('');
  const [salary, setSalary] = useState('');
  const [location, setLocation] = useState('');
  const [deadline, setDeadline] = useState('');
  const [loading, setLoading] = useState(false);
  const [feedback, setFeedback] = useState('');

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    try {
      await postJob({ title, description, requirements, salary, location, deadline });
      setFeedback('Job posted successfully!');
    } catch (error) {
      setFeedback('Failed to post job. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="max-w-3xl mx-auto p-6 bg-gray-950 text-white rounded-xl shadow-md">
      <h1 className="text-2xl font-bold mb-4">Post a New Job</h1>
      {loading && <LoadingSpinner />}
      {feedback && <p className="text-green-500 mb-4">{feedback}</p>}
      <form onSubmit={handleSubmit} className="flex flex-col gap-4">
        <input
          type="text"
          placeholder="Job Title"
          value={title}
          onChange={(e) => setTitle(e.target.value)}
          className="p-3 rounded-lg bg-gray-800 text-white border border-gray-700 focus:outline-none focus:border-indigo-500"
          required
        />
        <textarea
          placeholder="Job Description"
          value={description}
          onChange={(e) => setDescription(e.target.value)}
          className="p-3 rounded-lg bg-gray-800 text-white border border-gray-700 focus:outline-none focus:border-indigo-500"
          required
        />
        <textarea
          placeholder="Requirements"
          value={requirements}
          onChange={(e) => setRequirements(e.target.value)}
          className="p-3 rounded-lg bg-gray-800 text-white border border-gray-700 focus:outline-none focus:border-indigo-500"
          required
        />
        <input
          type="text"
          placeholder="Salary Range"
          value={salary}
          onChange={(e) => setSalary(e.target.value)}
          className="p-3 rounded-lg bg-gray-800 text-white border border-gray-700 focus:outline-none focus:border-indigo-500"
          required
        />
        <input
          type="text"
          placeholder="Location"
          value={location}
          onChange={(e) => setLocation(e.target.value)}
          className="p-3 rounded-lg bg-gray-800 text-white border border-gray-700 focus:outline-none focus:border-indigo-500"
          required
        />
        <input
          type="date"
          value={deadline}
          onChange={(e) => setDeadline(e.target.value)}
          className="p-3 rounded-lg bg-gray-800 text-white border border-gray-700 focus:outline-none focus:border-indigo-500"
          required
        />
        <button
          type="submit"
          className="px-4 py-2 rounded-lg bg-indigo-600 text-white hover:bg-indigo-500 transition"
        >
          Post Job
        </button>
      </form>
    </div>
  );
};

export default PostJobPage;

