  return (
    <div className="bg-gray-800 text-white p-4 rounded-xl shadow-md hover:shadow-lg transition">
      <h3 className="text-xl font-semibold mb-2">{job?.title ?? 'Unknown Title'}</h3>
      <p className="text-gray-400 mb-1">{job?.company ?? 'Unknown Company'}</p>
      <p className="text-gray-400 mb-1">{job?.location ?? 'Unknown Location'}</p>
      <p className="text-gray-400">{job?.salary ?? 'Salary not specified'}</p>
    </div>
  );
};

export default JobCard;

